/// Benchmark suite for rvq-index.
///
/// Expects benchmark data in benchmarks/data/ (generated by benchmarks/generate_data.py):
///   codebooks.npy          float32 (num_books, num_codes, dim)
///   codebooks.safetensors  same data, key "codebooks"
///   entity_codes.npy       uint16  (N, num_books)
///   entity_ids.npy         int64   (N,)
///   query_embeddings.npy   float32 (Q, dim)
///   query_gt.npy           int64   (Q, K)
///
/// Run:
///   cargo bench --features npy,safetensors
use std::fs::File;
use std::io::BufReader;
use std::path::Path;

use criterion::{Criterion, criterion_group, criterion_main};
use npyz::NpyFile;
use rvq_index::codebook::{Code, CodeBooks};
use rvq_index::index::RvqIndex;

const DATA_DIR: &str = "benchmarks/data";
const RECALL_K: usize = 10;

const CODEBOOKS_NPY: &str = "codebooks.npy";
const CODEBOOKS_SAFETENSORS: &str = "codebooks.safetensors";
const CODEBOOKS_TENSOR_KEY: &str = "codebooks";
const ENTITY_CODES_NPY: &str = "entity_codes.npy";
const QUERY_EMBEDDINGS_NPY: &str = "query_embeddings.npy";
const QUERY_GT_NPY: &str = "query_gt.npy";
const QUERY_GT_QUANTIZED_NPY: &str = "query_gt_quantized.npy";

// Helpers to load numpy files
fn load_npy(path: impl AsRef<Path>) -> NpyFile<BufReader<File>> {
    let file = std::fs::File::open(path).expect("open npy");
    let reader = std::io::BufReader::new(file);
    let npy = npyz::NpyFile::new(reader).expect("parse npy");
    npy
}

fn load_npy_f32(path: impl AsRef<Path>) -> (Vec<f32>, Vec<usize>) {
    let npy = load_npy(path);
    let shape: Vec<usize> = npy.shape().iter().map(|&x| x as usize).collect();
    let data: Vec<f32> = npy.into_vec().expect("read npy f32");
    (data, shape)
}

fn load_npy_i64(path: impl AsRef<Path>) -> (Vec<i64>, Vec<usize>) {
    let npy = load_npy(path);
    let shape: Vec<usize> = npy.shape().iter().map(|&x| x as usize).collect();
    let data: Vec<i64> = npy.into_vec().expect("read npy i64");
    (data, shape)
}

fn load_npy_u16(path: impl AsRef<Path>) -> (Vec<u16>, Vec<usize>) {
    let npy = load_npy(path);
    let shape: Vec<usize> = npy.shape().iter().map(|&x| x as usize).collect();
    let data: Vec<u16> = npy.into_vec().expect("read npy u16");
    (data, shape)
}

fn build_index(
    codebooks: CodeBooks<f32>,
    entity_codes: &[u16],
    num_books: usize,
) -> RvqIndex<i64, f32> {
    let n = entity_codes.len() / num_books;
    let mut index = RvqIndex::new(codebooks);
    index
        .insert_many((0..n as i64).map(|id| {
            let offset = id as usize * num_books;
            let codes: Vec<Code> = entity_codes[offset..offset + num_books]
                .iter()
                .map(|&c| c as Code)
                .collect();
            (id, codes)
        }))
        .expect("insert_many");
    index
}

// Benchmarks
fn bench_creation_npy(c: &mut Criterion) {
    let data_dir = Path::new(DATA_DIR);
    let (entity_codes_flat, ec_shape) = load_npy_u16(data_dir.join("entity_codes.npy"));
    let num_books = ec_shape[1];

    c.bench_function("creation_npy", |b| {
        b.iter(|| {
            let cb = CodeBooks::<f32>::from_npy(data_dir.join(CODEBOOKS_NPY))
                .expect("load codebooks npy");
            build_index(cb, &entity_codes_flat, num_books)
        })
    });
}

fn bench_creation_safetensors(c: &mut Criterion) {
    let data_dir = Path::new(DATA_DIR);
    let (entity_codes_flat, ec_shape) = load_npy_u16(data_dir.join("entity_codes.npy"));
    let num_books = ec_shape[1];

    c.bench_function("creation_safetensors", |b| {
        b.iter(|| {
            let cb = CodeBooks::<f32>::from_safetensors(
                data_dir.join(CODEBOOKS_SAFETENSORS),
                CODEBOOKS_TENSOR_KEY,
            )
            .expect("load codebooks safetensors");
            build_index(cb, &entity_codes_flat, num_books)
        })
    });
}

fn bench_query(c: &mut Criterion) {
    let data_dir = Path::new(DATA_DIR);

    let (entity_codes_flat, ec_shape) = load_npy_u16(data_dir.join(ENTITY_CODES_NPY));
    let num_books = ec_shape[1];

    let cb = CodeBooks::<f32>::from_npy(data_dir.join(CODEBOOKS_NPY)).expect("load codebooks");
    let index = build_index(cb, &entity_codes_flat, num_books);

    let (query_flat, q_shape) = load_npy_f32(data_dir.join(QUERY_EMBEDDINGS_NPY));
    let dim = q_shape[1];
    let queries: Vec<Vec<f32>> = query_flat.chunks_exact(dim).map(|c| c.to_vec()).collect();
    let query_slices: Vec<&[f32]> = queries.iter().map(|q| q.as_slice()).collect();

    // Single query
    c.bench_function("query_single", |b| {
        b.iter(|| index.search(&queries[0], RECALL_K).expect("search"))
    });

    // Batch query
    c.bench_function("query_batch", |b| {
        b.iter(|| {
            index
                .search_batch(&query_slices, RECALL_K)
                .expect("search_batch")
        })
    });
}

fn bench_recall(_: &mut Criterion) {
    let data_dir = Path::new(DATA_DIR);

    let (entity_codes_flat, ec_shape) = load_npy_u16(data_dir.join(ENTITY_CODES_NPY));
    let num_books = ec_shape[1];

    let cb = CodeBooks::<f32>::from_npy(data_dir.join(CODEBOOKS_NPY)).expect("load codebooks");
    let index = build_index(cb, &entity_codes_flat, num_books);

    let (query_flat, q_shape) = load_npy_f32(data_dir.join(QUERY_EMBEDDINGS_NPY));
    let dim = q_shape[1];
    let queries: Vec<Vec<f32>> = query_flat.chunks_exact(dim).map(|c| c.to_vec()).collect();
    let query_slices: Vec<&[f32]> = queries.iter().map(|q| q.as_slice()).collect();

    let (gt_latent_flat, gt_latent_shape) = load_npy_i64(data_dir.join(QUERY_GT_NPY));
    let (gt_quant_flat, gt_quant_shape) = load_npy_i64(data_dir.join(QUERY_GT_QUANTIZED_NPY));

    // Compute recall (not timed — runs once and prints)
    let results = index
        .search_batch(&query_slices, RECALL_K)
        .expect("search_batch");
    let num_queries = queries.len();

    let recall_at_k = |gt_flat: &[i64], gt_k: usize| -> (f64, usize) {
        let mut hits = 0usize;
        for (q_idx, res) in results.iter().enumerate() {
            let gt_start = q_idx * gt_k;
            let gt_ids: std::collections::HashSet<i64> = gt_flat
                [gt_start..gt_start + gt_k.min(RECALL_K)]
                .iter()
                .copied()
                .collect();
            for id in res {
                if gt_ids.contains(*id) {
                    hits += 1;
                }
            }
        }
        (hits as f64 / (num_queries * RECALL_K) as f64, hits)
    };

    let (recall_quant, hits_quant) = recall_at_k(&gt_quant_flat, gt_quant_shape[1]);
    let (recall_latent, hits_latent) = recall_at_k(&gt_latent_flat, gt_latent_shape[1]);
    // Should be 1 - used to verify the implementation
    println!(
        "Recall@{RECALL_K} (quantized space) = {recall_quant:.4} ({hits_quant}/{} hits)",
        num_queries * RECALL_K
    );
    println!(
        "Recall@{RECALL_K} (latent space) = {recall_latent:.4} ({hits_latent}/{} hits)",
        num_queries * RECALL_K
    );
}

criterion_group!(
    benches,
    bench_creation_npy,
    bench_creation_safetensors,
    bench_query,
    bench_recall
);
criterion_main!(benches);
